import{c as o,Q as a,j as d,m as c}from"./chunks/framework.BkjtU8k0.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1780018488000}'),i={name:"guide/faq.md"};function l(r,e,t,s,p,h){return a(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="vue、react-和纯-js-应该安装哪个包" tabindex="-1">Vue、React 和纯 JS 应该安装哪个包 <a class="header-anchor" href="#vue、react-和纯-js-应该安装哪个包" aria-label="Permalink to &quot;Vue、React 和纯 JS 应该安装哪个包&quot;">​</a></h2><p>Vue3 项目安装 <code>@flyfish-group/file-viewer3@1.0.14</code>，使用 <code>createApp(App).use(FileViewer)</code> 注册。Vue2.7 项目安装 <code>@flyfish-group/file-viewer@1.0.14</code>，使用 <code>Vue.use(FileViewer)</code> 注册。</p><p>React 项目安装 <code>@flyfish-group/file-viewer-react@1.0.14</code>，纯 JS 或非框架页面安装 <code>@flyfish-group/file-viewer-web@1.0.14</code>。React 和纯 JS 包只做 iframe 集成，默认加载宿主项目里的 <code>/file-viewer/index.html</code>，预览能力来自 Vue3 基线构建产物。</p><p>React / 纯 JS 包推荐用 <code>npm install</code>，安装后会自动复制 viewer 静态产物。pnpm 10 如果提示 <code>Ignored build scripts: @flyfish-group/file-viewer-web</code>，请执行 <code>pnpm approve-builds</code>，或运行 <code>pnpm exec file-viewer-copy-assets ./public/file-viewer</code>。</p><p>所有包线的格式能力、示例文件、<code>file</code> / <code>url</code> 参数行为和 iframe 协议保持一致。</p><p>Vue3 和 Vue2 的安装器都会自动带上样式，不需要额外 import CSS。</p><h2 id="url-预览为什么失败或空白" tabindex="-1">URL 预览为什么失败或空白 <a class="header-anchor" href="#url-预览为什么失败或空白" aria-label="Permalink to &quot;URL 预览为什么失败或空白&quot;">​</a></h2><p>组件在浏览器里通过 <code>axios</code> 请求目标文件，所以最常见的失败原因是:</p><ul><li>文件地址本身不可访问</li><li>服务端没有正确配置 CORS</li><li>鉴权信息只能在宿主系统内使用，浏览器直接请求拿不到文件</li></ul><p>如果你的场景带有登录态、签名 URL 或内部权限体系，优先使用 <code>file</code> 参数或 <a href="/guide/iframe">Iframe 嵌入</a>。</p><h2 id="react-或纯-js-集成后为什么页面空白" tabindex="-1">React 或纯 JS 集成后为什么页面空白 <a class="header-anchor" href="#react-或纯-js-集成后为什么页面空白" aria-label="Permalink to &quot;React 或纯 JS 集成后为什么页面空白&quot;">​</a></h2><p>这通常是私有化 viewer 静态产物没有被部署出来。默认情况下，React 和纯 JS 包会加载:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/file-viewer/index.html</span></span>\n<span class="line"><span>/file-viewer/assets/*</span></span></code></pre></div><p>如果你的包管理器没有执行安装脚本，或者静态目录不是 <code>public/file-viewer</code>，请运行:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file-viewer-copy-assets</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./public/vendor/file-viewer</span></span></code></pre></div><p>然后在组件或 helper 中传入 <code>viewerUrl=&quot;/vendor/file-viewer/index.html&quot;</code>。</p><h2 id="为什么带查询参数的下载地址有时识别不到格式" tabindex="-1">为什么带查询参数的下载地址有时识别不到格式 <a class="header-anchor" href="#为什么带查询参数的下载地址有时识别不到格式" aria-label="Permalink to &quot;为什么带查询参数的下载地址有时识别不到格式&quot;">​</a></h2><p>当前预览器会根据文件名扩展名判断该走哪条渲染链路。如果 URL 形如 <code>/download?id=123</code>，路径里没有明确的 <code>.pdf</code>、<code>.docx</code>、<code>.xlsx</code> 这类后缀，渲染器就很难准确识别文件类型。</p><p>这类地址最稳妥的做法是:</p><ul><li>先在业务侧请求文件</li><li>拿到 <code>Blob</code> 或 <code>ArrayBuffer</code></li><li>再包装成带正确文件名的 <code>File</code></li></ul><h2 id="为什么一定要给父容器设置高度" tabindex="-1">为什么一定要给父容器设置高度 <a class="header-anchor" href="#为什么一定要给父容器设置高度" aria-label="Permalink to &quot;为什么一定要给父容器设置高度&quot;">​</a></h2><p>预览器默认使用 <code>width: 100%</code> 和 <code>height: 100%</code> 填满父容器。如果父容器没有稳定高度，渲染区域就会塌陷，看起来像“没有内容”。</p><h2 id="file-和-url-同时传时-谁优先" tabindex="-1"><code>file</code> 和 <code>url</code> 同时传时，谁优先 <a class="header-anchor" href="#file-和-url-同时传时-谁优先" aria-label="Permalink to &quot;`file` 和 `url` 同时传时，谁优先&quot;">​</a></h2><p>当前行为是 <code>file</code> 优先。如果后续把 <code>file</code> 清空，而 <code>url</code> 仍然存在，组件会回退到 <code>url</code> 再次加载。</p><h2 id="doc-和-docx-的渲染实现一样吗" tabindex="-1"><code>.doc</code> 和 <code>.docx</code> 的渲染实现一样吗 <a class="header-anchor" href="#doc-和-docx-的渲染实现一样吗" aria-label="Permalink to &quot;`.doc` 和 `.docx` 的渲染实现一样吗&quot;">​</a></h2><p>不一样。</p><ul><li><code>docx</code> 使用 <code>docx-preview</code></li><li><code>doc</code> 使用 <code>msdoc-viewer</code></li></ul><p>另外，<code>.doc</code> 还额外套了一层 Word 风格页面容器，让页面在灰色背景中居中展示。</p><h2 id="blob-或-arraybuffer-能直接传给-file-吗" tabindex="-1"><code>Blob</code> 或 <code>ArrayBuffer</code> 能直接传给 <code>file</code> 吗 <a class="header-anchor" href="#blob-或-arraybuffer-能直接传给-file-吗" aria-label="Permalink to &quot;`Blob` 或 `ArrayBuffer` 能直接传给 `file` 吗&quot;">​</a></h2><p>从接入经验上看，不建议直接把裸 <code>Blob</code> 或 <code>ArrayBuffer</code> 塞进去。</p><p>原因很简单: 预览器要靠文件名扩展名来选择渲染器，而裸二进制本身通常不带可靠的文件名。更稳妥的方式是:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> file</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> File</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([blobOrBuffer], </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;report.xlsx&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>这样既保留了二进制链路，也把渲染器最依赖的扩展名补齐了。</p><h2 id="xls-和-xlsx-的样式能力有什么差异" tabindex="-1"><code>xls</code> 和 <code>xlsx</code> 的样式能力有什么差异 <a class="header-anchor" href="#xls-和-xlsx-的样式能力有什么差异" aria-label="Permalink to &quot;`xls` 和 `xlsx` 的样式能力有什么差异&quot;">​</a></h2><p>当前表格预览统一走 <code>styled-exceljs</code>，会读取文件里能表达的列宽、行高、合并单元格、边框、填充和对齐等信息。差异主要来自格式本身: <code>xlsx</code> 通常保存的样式信息更完整，而 <code>xls/csv/ods</code> 等格式可能缺少部分现代样式描述。</p><h2 id="html-文件为什么是按文本显示的" tabindex="-1"><code>html</code> 文件为什么是按文本显示的 <a class="header-anchor" href="#html-文件为什么是按文本显示的" aria-label="Permalink to &quot;`html` 文件为什么是按文本显示的&quot;">​</a></h2><p>因为当前版本把 <code>html</code> 放在代码/文本类型里处理，它会展示并高亮源内容，而不会把文件当作网页直接执行。这是为了保证预览行为更安全、更可控，也更适合代码和模板查看。</p><h2 id="dwg-能直接预览吗" tabindex="-1">DWG 能直接预览吗 <a class="header-anchor" href="#dwg-能直接预览吗" aria-label="Permalink to &quot;DWG 能直接预览吗&quot;">​</a></h2><p>DXF 当前走 <code>@cadview/core</code> 在浏览器端直接预览。DWG 会先做兼容处理: 如果文件内容其实是 DXF 文本，会直接按 DXF 打开；如果是真 DWG 二进制，会尝试提取文件内嵌 PNG/JPEG/BMP 预览图并展示。</p><p>真实 DWG 的完整矢量图元和几何解析仍建议在业务侧转换为 DXF。原因是 DWG 是专有二进制格式，常见前端解析器存在 GPL 授权约束或需要闭源 SDK / 转换运行时，当前 Apache-2.0 npm 包不会默认打入这些依赖。</p><h2 id="_3d-模型支持哪些格式" tabindex="-1">3D 模型支持哪些格式 <a class="header-anchor" href="#_3d-模型支持哪些格式" aria-label="Permalink to &quot;3D 模型支持哪些格式&quot;">​</a></h2><p>3D 模型走 Three.js 按需渲染，当前支持 <code>glb</code>、<code>gltf</code>、<code>obj</code>、<code>stl</code>、<code>ply</code>、<code>fbx</code>、<code>dae</code>、<code>3ds</code>、<code>3mf</code>、<code>amf</code>、<code>usd</code>、<code>usda</code>、<code>usdc</code>、<code>usdz</code>、<code>kmz</code>、<code>pcd</code>、<code>wrl</code>、<code>vrml</code>、<code>xyz</code>、<code>vtk</code>、<code>vtp</code>。如果模型依赖外部贴图、材质或 <code>.bin</code>，远程 URL 预览会按原文件目录继续加载；本地上传建议优先使用单文件 <code>.glb</code>。<code>step</code>、<code>stp</code>、<code>iges</code>、<code>igs</code>、<code>ifc</code>、<code>3dm</code> 会进入 3D 预览器并说明为什么需要私有转换链路。</p><h2 id="excalidraw-和-draw-io-是怎么预览的" tabindex="-1">Excalidraw 和 draw.io 是怎么预览的 <a class="header-anchor" href="#excalidraw-和-draw-io-是怎么预览的" aria-label="Permalink to &quot;Excalidraw 和 draw.io 是怎么预览的&quot;">​</a></h2><p><code>.excalidraw</code> 走官方 <code>@excalidraw/excalidraw</code> 包的 <code>exportToSvg</code>，<code>.drawio</code> / <code>.dio</code> 走官方 diagrams.net <code>GraphViewer</code>。组件不会手写绘图格式解析器，只负责按需加载第三方开源能力、挂载预览容器和显示错误提示。</p><h2 id="压缩包能预览到什么程度" tabindex="-1">压缩包能预览到什么程度 <a class="header-anchor" href="#压缩包能预览到什么程度" aria-label="Permalink to &quot;压缩包能预览到什么程度&quot;">​</a></h2><p>压缩包走 <code>libarchive.js</code> 的 WASM Worker，支持 ZIP、7z、RAR、TAR、GZIP、BZIP2、XZ、CAB、ISO、JAR、APK、CBZ/CBR 等入口。组件先读取目录，用户点击内部文件后才按需解压，避免一次性把大包展开到主线程。</p><p>内部文件会继续复用统一预览器，所以压缩包里的 PDF、Office、Markdown、代码、图片、邮件或嵌套压缩包都可以在体积限制内打开。私有化部署时请确认 <code>worker-bundle.js</code> 和同目录的 <code>libarchive.wasm</code> 能访问，或通过 <code>options.archive.workerUrl</code> 指定路径。</p><h2 id="邮件和-eda-文件怎么预览" tabindex="-1">邮件和 EDA 文件怎么预览 <a class="header-anchor" href="#邮件和-eda-文件怎么预览" aria-label="Permalink to &quot;邮件和 EDA 文件怎么预览&quot;">​</a></h2><p><code>.eml</code> 使用 <code>postal-mime</code>，<code>.msg</code> 使用 <code>@kenjiuno/msgreader</code>。邮件预览会展示头信息、HTML/文本正文和附件列表；附件可以下载，也可以继续交给统一预览器打开。HTML 正文会放进 sandbox iframe，不执行脚本。</p><p><code>.olb</code> / <code>.dra</code> 使用 <code>cfb</code> 解析常见 OrCAD / Allegro 复合文档容器，展示结构树、元件/封装/Padstack 候选、属性、诊断、文本片段和可读字符串。它适合做附件初筛，不替代专业 EDA 软件里的封装编辑、电气规则校核或制造输出。</p><h2 id="水印、打印和导出怎么配置" tabindex="-1">水印、打印和导出怎么配置 <a class="header-anchor" href="#水印、打印和导出怎么配置" aria-label="Permalink to &quot;水印、打印和导出怎么配置&quot;">​</a></h2><p>通过 <code>options</code> 配置即可。<code>options.watermark</code> 支持文字或图片水印，<code>options.toolbar</code> 可以控制下载原文件、打印完整渲染内容和导出渲染后 HTML。打印和 HTML 导出会基于当前浏览器渲染结果生成，不会修改原始文件；PDF 会通过专属导出适配器逐页生成完整页面，避免只打印当前视口、当前页或被滚动容器裁切。</p><h2 id="为什么-pdf-打印不是当前屏幕截图" tabindex="-1">为什么 PDF 打印不是当前屏幕截图 <a class="header-anchor" href="#为什么-pdf-打印不是当前屏幕截图" aria-label="Permalink to &quot;为什么 PDF 打印不是当前屏幕截图&quot;">​</a></h2><p>从 <code>1.0.12</code> 起，PDF 的打印和导出 HTML 不再克隆当前可见 canvas，而是重新按页生成完整 PDF 页面。这样即使用户只滚动到第一页、开启了导航窗格，或当前视口里只渲染了部分页面，打印窗口和导出的 HTML 仍然会包含完整页序。</p><h2 id="epub、umd-和音频是怎么预览的" tabindex="-1">EPUB、UMD 和音频是怎么预览的 <a class="header-anchor" href="#epub、umd-和音频是怎么预览的" aria-label="Permalink to &quot;EPUB、UMD 和音频是怎么预览的&quot;">​</a></h2><p><code>.epub</code> 走 <code>epubjs</code>，用于解析 EPUB 包、目录和章节资源。阅读区默认使用滚动文档模式，兼容性比超宽分页 iframe 更稳，避免部分浏览器出现正文白板。当前不内置 Kindle 专有格式或 DRM 电子书解析，建议在业务侧转换为 EPUB / PDF。</p><p><code>.umd</code> 走独立 UMD 电子书解析器。前端生态里没有可靠维护的 UMD 阅读整库，所以组件按文件结构解析元数据、章节偏移、章节标题和 zlib 正文段，并用 <code>pako</code> 解压正文后按 UTF-16LE 展示。</p><p>音频文件走浏览器原生 <code>&lt;audio&gt;</code>，支持 <code>mp3</code>、<code>mpeg</code>、<code>wav</code>、<code>ogg</code>、<code>oga</code>、<code>opus</code>、<code>m4a</code>、<code>aac</code>、<code>flac</code>、<code>weba</code> 等扩展名入口。实际能否播放取决于浏览器对具体编码的支持，跨端最稳妥的是 MP3 或 OGG。</p><h2 id="pptx-复杂模板能还原到什么程度" tabindex="-1">PPTX 复杂模板能还原到什么程度 <a class="header-anchor" href="#pptx-复杂模板能还原到什么程度" aria-label="Permalink to &quot;PPTX 复杂模板能还原到什么程度&quot;">​</a></h2><p>PPTX 是浏览器端近似渲染，不依赖 Office 本体。当前已经增强组合图形坐标、旋转/翻转、主题背景、图片裁剪和 EMF 矢量图片转换，适合汇报材料、课件和方案回看。动画、宏、嵌入式对象和极复杂的专有 Office 特效仍建议导出 PDF，或把真实业务样本加入上线前回归。</p><h2 id="代码文件会执行吗" tabindex="-1">代码文件会执行吗 <a class="header-anchor" href="#代码文件会执行吗" aria-label="Permalink to &quot;代码文件会执行吗&quot;">​</a></h2><p>不会。代码/文本链路使用 <code>highlight.js</code> 做源码高亮，只展示内容，不执行 <code>html</code>、<code>js</code> 或模板里的脚本。</p><h2 id="大小写扩展名会影响识别吗" tabindex="-1">大小写扩展名会影响识别吗 <a class="header-anchor" href="#大小写扩展名会影响识别吗" aria-label="Permalink to &quot;大小写扩展名会影响识别吗&quot;">​</a></h2><p>不会。扩展名匹配时会统一转成小写，所以 <code>PDF</code>、<code>DocX</code>、<code>SVG</code> 这类大小写差异不会影响命中。</p><h2 id="为什么-ppt-不能像-pptx-一样直接打开" tabindex="-1">为什么 <code>ppt</code> 不能像 <code>pptx</code> 一样直接打开 <a class="header-anchor" href="#为什么-ppt-不能像-pptx-一样直接打开" aria-label="Permalink to &quot;为什么 `ppt` 不能像 `pptx` 一样直接打开&quot;">​</a></h2><p>当前内置的是 <code>pptx</code> 渲染链路，老的二进制 <code>ppt</code> 并没有注册对应处理器。如果你的业务里大量存在 <code>ppt</code>，建议在接入侧先做格式转换，或者统一导出为 <code>pptx</code> / <code>pdf</code>。</p><h2 id="iframe-模式为什么要带-from" tabindex="-1">iframe 模式为什么要带 <code>from</code> <a class="header-anchor" href="#iframe-模式为什么要带-from" aria-label="Permalink to &quot;iframe 模式为什么要带 `from`&quot;">​</a></h2><p>这是为了限制消息来源。预览器接收 <code>Blob</code> 时会校验 <code>event.origin === from</code>，只有来源匹配才会渲染，这样能避免任意页面向 iframe 注入数据。</p><h2 id="大文件会不会慢" tabindex="-1">大文件会不会慢 <a class="header-anchor" href="#大文件会不会慢" aria-label="Permalink to &quot;大文件会不会慢&quot;">​</a></h2><p>会，尤其是复杂的 Office 文档、大体积 PDF 和大型压缩包。因为解析发生在浏览器里，最终体验取决于:</p><ul><li>文件体积和复杂度</li><li>当前设备的 CPU 和内存</li><li>浏览器本身的性能</li></ul><p>如果你的业务里经常处理超大文件，建议优先用真实样本做联调测试，并为压缩包配置 <code>options.archive.maxArchiveSize</code> 和 <code>options.archive.maxEntryPreviewSize</code>。</p><h2 id="公开仓库里为什么没有源码" tabindex="-1">公开仓库里为什么没有源码 <a class="header-anchor" href="#公开仓库里为什么没有源码" aria-label="Permalink to &quot;公开仓库里为什么没有源码&quot;">​</a></h2><p>公开 GitHub 仓库面向“成品分发”，提供的是混淆压缩后的组件库、可部署 Demo、文档静态产物、完整示例文件和 tarball。需要源码、二开包或商业自助开通的用户，可以前往 <a href="https://dev.flyfish.group/shop" target="_blank" rel="noreferrer">https://dev.flyfish.group/shop</a>，付费 4.99 后自助开通。</p><h2 id="二开或商用需要注意什么" tabindex="-1">二开或商用需要注意什么 <a class="header-anchor" href="#二开或商用需要注意什么" aria-label="Permalink to &quot;二开或商用需要注意什么&quot;">​</a></h2><p>项目使用 <code>Apache-2.0</code> 许可证。二开或商用时，请保留许可证、版权和来源说明，并注明项目来源为 Flyfish Viewer / <code>@flyfish-group/file-viewer3</code> 或 <code>@flyfish-group/file-viewer</code>。如果修复了通用问题或增强了通用能力，建议通过 issue / PR 贡献回来。</p>',77)])])}const f=o(i,[["render",l]]);export{u as __pageData,f as default};
